import { useState, useEffect } from "react";
import { Link } from "react-router-dom";
import API from "../../services/api";
import "./css/UserDashboard.css";
import "./css/UploadResume.css";

function UserResume() {
  const [resumeData, setResumeData] = useState(null);
  const [loading, setLoading] = useState(true);
  const [noData, setNoData] = useState(false);

  useEffect(() => {
    fetchResume();
  }, []);

  const fetchResume = async () => {
    try {
      const res = await API.get("/user/resume");
      if (res.data && res.data.message) {
        setNoData(true);
      } else {
        setResumeData(res.data);
      }
    } catch (e) {
      console.error(e);
      setNoData(true);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="dashboard-layout">
      <aside className="dashboard-sidebar">
        <div className="sidebar-logo">
          <div className="logo-icon">RA</div>
          ResumeAlert
        </div>

        <nav className="nav-menu">
          <Link to="/user/dashboard" className="nav-link">🏠 Dashboard</Link>
          <Link to="/user/resume" className="nav-link active">📄 My Resume</Link>
          <Link to="/user/upload-resume" className="nav-link">⬆️ Upload Resume</Link>
          <Link to="/user/alerts" className="nav-link">🔔 Job Alerts</Link>
          <Link to="/user/saved-jobs" className="nav-link">⭐ Saved Jobs</Link>
          <Link to="/user/account" className="nav-link">⚙️ Account</Link>
        </nav>

        <div className="sidebar-footer">
          <Link to="/" style={{ textDecoration: "none" }}>
            <button className="sign-out-btn">🚪 Sign Out</button>
          </Link>
        </div>
      </aside>

      <main className="dashboard-main">
        <header className="dashboard-header-flex">
          <div className="header-titles">
            <h1>My Resume 📄</h1>
            <p>Your currently uploaded profile and extracted skill tags. 📊</p>
          </div>
          <div>
            <Link to="/user/upload-resume">
              <button className="ur-upload-btn" style={{ width: "auto", padding: "0.6rem 1.2rem" }}>
                ⬆️ Upload New Resume
              </button>
            </Link>
          </div>
        </header>

        {loading && <p style={{ color: "var(--text-secondary)" }}>Loading resume details…</p>}

        {noData && !loading && (
          <div className="ur-card" style={{ maxWidth: "480px", textAlign: "center" }}>
            <div style={{ fontSize: "3rem", marginBottom: "0.75rem" }}>📂</div>
            <h3 style={{ color: "var(--text-primary)", marginBottom: "0.5rem" }}>No Resume Found</h3>
            <p style={{ color: "var(--text-secondary)", fontSize: "0.9rem", marginBottom: "1.25rem" }}>
              Upload your first resume to see your extracted profile here.
            </p>
            <Link to="/user/upload-resume">
              <button className="ur-upload-btn">⬆️ Upload Resume</button>
            </Link>
          </div>
        )}

        {resumeData && !loading && (
          <div style={{ maxWidth: "820px" }}>
            {/* Header Card */}
            <div className="update-resume-card hover-lift" style={{ marginBottom: "1.5rem" }}>
              <div style={{ display: "flex", alignItems: "center", gap: "1rem", borderBottom: "1px solid var(--border-color)", paddingBottom: "1.5rem", marginBottom: "1.5rem" }}>
                <div style={{ width: "64px", height: "64px", background: "var(--primary-light)", color: "var(--primary-color)", borderRadius: "var(--radius-md)", display: "flex", alignItems: "center", justifyContent: "center", fontSize: "2rem", fontWeight: 700 }}>
                  📄
                </div>
                <div>
                  <h2 style={{ color: "var(--text-primary)", fontSize: "1.25rem" }}>
                    {resumeData.name ? `${resumeData.name}'s Resume` : "Uploaded Resume"}
                  </h2>
                  <p style={{ color: "var(--text-secondary)", fontSize: "0.8rem" }}>
                    File: {resumeData.filename || "—"} &bull; Uploaded: {resumeData.uploaded_at ? new Date(resumeData.uploaded_at).toLocaleString() : "recently"}
                  </p>
                </div>
              </div>

              {/* Contact Info */}
              <div className="ur-result-grid">
                {resumeData.email && (
                  <div className="ur-result-item">
                    <div className="ur-result-label">✉️ Email</div>
                    <div className="ur-result-value">{resumeData.email}</div>
                  </div>
                )}
                {resumeData.phone && (
                  <div className="ur-result-item">
                    <div className="ur-result-label">📞 Phone</div>
                    <div className="ur-result-value">{resumeData.phone}</div>
                  </div>
                )}
              </div>

              {/* Skills */}
              {resumeData.skills && resumeData.skills.length > 0 && (
                <div className="extracted-profile" style={{ marginTop: "1.25rem" }}>
                  <div className="ep-title">🛠 EXTRACTED SKILLS</div>
                  <div className="badges-row">
                    {resumeData.skills.map((s, i) => (
                      <span key={i} className="tech-badge">{s}</span>
                    ))}
                  </div>
                </div>
              )}

              {/* CGPA */}
              {resumeData.cgpa && (
                <div className="cgpa-row" style={{ marginTop: "1.25rem" }}>
                  <div className="cgpa-label">🎓 System Verified CGPA:</div>
                  <div className="cgpa-value">{resumeData.cgpa}</div>
                </div>
              )}
            </div>

            {/* Education & Experience */}
            <div className="ur-page-grid">
              {resumeData.education && resumeData.education.length > 0 && (
                <div className="ur-card">
                  <div className="ur-card-title">🏫 Education</div>
                  <ul className="ur-list">
                    {resumeData.education.map((e, i) => (
                      <li key={i}>{e}</li>
                    ))}
                  </ul>
                </div>
              )}

              {resumeData.experience && resumeData.experience.length > 0 && (
                <div className="ur-card">
                  <div className="ur-card-title">💼 Experience</div>
                  <ul className="ur-list">
                    {resumeData.experience.map((ex, i) => (
                      <li key={i}>{ex}</li>
                    ))}
                  </ul>
                </div>
              )}
            </div>
          </div>
        )}
      </main>
    </div>
  );
}

export default UserResume;
